'use client'

import { useState } from 'react'
import { format } from 'date-fns'
import type { ColDef, ValueFormatterParams } from 'ag-grid-community'
import { DataTable } from '@/components/ui/data-table'
import { Button } from '@/components/ui/button'
import type { DomainItem } from '@/features/domain/types'
import { DomainForm } from './DomainForm'
import { DomainDetailPanel } from './DomainDetailPanel'

interface DomainTableProps {
    items: DomainItem[]
    total: number
    page: number
    size: number
}

const columnDefs: ColDef<DomainItem>[] = [
    { field: 'code', headerName: '도메인코드', width: 150 },
    { field: 'name', headerName: '도메인명', flex: 1 },
    { field: 'description', headerName: '설명', flex: 1 },
    {
        field: 'createdAt',
        headerName: '등록일',
        width: 150,
        valueFormatter: (params: ValueFormatterParams<DomainItem, Date>) =>
            params.value ? format(new Date(params.value), 'yyyy-MM-dd') : '',
    },
]

export function DomainTable({ items }: DomainTableProps) {
    const [createOpen, setCreateOpen] = useState(false)
    const [selectedDomain, setSelectedDomain] = useState<DomainItem | null>(null)
    const [detailOpen, setDetailOpen] = useState(false)

    const handleRowClick = (row: DomainItem) => {
        setSelectedDomain(row)
        setDetailOpen(true)
    }

    return (
        <div>
            <div className="flex justify-end mb-2">
                <Button onClick={() => setCreateOpen(true)}>새 도메인</Button>
            </div>

            <DataTable<DomainItem>
                columnDefs={columnDefs}
                rowData={items}
                onRowClick={handleRowClick}
            />

            <DomainForm
                open={createOpen}
                onOpenChange={setCreateOpen}
                onSuccess={() => {}}
            />

            <DomainDetailPanel
                domain={selectedDomain}
                open={detailOpen}
                onOpenChange={setDetailOpen}
            />
        </div>
    )
}

