import { getDomains } from '@/features/domain/queries'
import { domainSearchSchema } from '@/features/domain/schema'
import { PageHeader } from '@/components/ui/page-header'
import { DomainSearchForm } from '@/features/domain/components/DomainSearchForm'
import { DomainTable } from '@/features/domain/components/DomainTable'

export default async function DomainPage({
    searchParams,
}: {
    searchParams: Promise<Record<string, string>>
}) {
    const params = domainSearchSchema.parse(await searchParams)
    const { items, total } = await getDomains(params)

    return (
        <div>
            <PageHeader title="도메인 관리" description={`총 ${total}건`} />
            <DomainSearchForm defaultKeyword={params.keyword} />
            <DomainTable items={items} total={total} page={params.page} size={params.size} />
        </div>
    )
}

